{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラを本日で正式キックオフし、プロジェクトを発足させる。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例会議を毎週水曜日の10時から1時間枠で開催する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "データ移行方針として、第1フェーズではマスタ系のみを移行し、トランザクション履歴は旧システムから参照する形とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "開発ベンダーの選定において、コマツバ・ソリューションズ株式会社を選択し、社内稟議を進める。",
      "decided_by": "郡司 明久"
    },
    {
      "id": "D5",
      "content": "認証およびマスタ配信の基盤構築について、サクラ商事との共同利用（第3案）の方針で進む。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "システム移行方式を、拠点をグループに分けて段階的に切り替える「段階移行」とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "本番リリース完了日を10月15日とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D8",
      "content": "システム切替作業は、土曜日の深夜帯に行う。",
      "decided_by": "沼田 賢一"
    },
    {
      "id": "D9",
      "content": "新システムにおけるユーザー権限のロール定義は既存を流用し、新規設計は行わず後日の改善課題とする。",
      "decided_by": "芦田 巧"
    },
    {
      "id": "D10",
      "content": "障害発生時の一次受け窓口をQAチーム（白鳥千夏）とする。",
      "decided_by": "桐生 遥"
    }
  ],
